func (qb *PostgresQueryBuilder) Select(fields ...string) QueryBuilder {
	var str string
	n := len(fields)

	if fields[0] == "*" {
		str = "*"
	} else {
		for i := 0; i < n; i++ {
			sli := strings.Split(fields[i], ".")
			s := strings.Join(sli, `"."`)
			s = fmt.Sprintf("%s%s%s", quote, s, quote)
			if n == 1 || i == n-1 {
				str += s
			} else {
				str += s + ","
			}
		}
	}

	qb.tokens = append(qb.tokens, "SELECT", str)
	return qb
}
